 1→export function formatMeasurement(mm) {
 2→  return `${(Math.abs(mm) / 1000).toFixed(2)} m`;
 3→}
 4→
 5→export function getAnnotationDisplayLabel(annotation) {
 6→  if (!annotation || annotation.type !== 'dimension') {
 7→    return annotation?.id || 'Annotation';
 8→  }
 9→
10→  const dx = annotation.endPoint.x - annotation.startPoint.x;
11→  const dy = annotation.endPoint.y - annotation.startPoint.y;
12→  let measurement = Math.hypot(dx, dy);
13→
14→  if (annotation.mode === 'horizontal') measurement = Math.abs(dx);
15→  if (annotation.mode === 'vertical') measurement = Math.abs(dy);
16→
17→  return annotation.textOverride?.trim() || `Dim ${formatMeasurement(measurement)}`;
18→}
