 1→import { TOOLS } from '@/editor/tools';
 2→import { distance } from '@/geometry/point';
 3→import { PREVIEW_LABEL_OFFSET } from '@/domain/defaults';
 4→
 5→export default function WallPreview({ toolState, activeTool }) {
 6→  if (activeTool !== TOOLS.WALL || !toolState.start || !toolState.preview) {
 7→    return null;
 8→  }
 9→
10→  const { start, preview } = toolState;
11→  const len = distance(start, preview);
12→  const label = (len / 1000).toFixed(2) + ' m';
13→  const midX = (start.x + preview.x) / 2;
14→  const midY = (start.y + preview.y) / 2;
15→
16→  return (
17→    <g className="wall-preview" style={{ pointerEvents: 'none' }}>
18→      <line
19→        x1={start.x} y1={start.y}
20→        x2={preview.x} y2={preview.y}
21→        stroke="var(--color-selection)"
22→        strokeWidth={2}
23→        strokeDasharray="8 4"
24→        vectorEffect="non-scaling-stroke"
25→        opacity={0.7}
26→      />
27→      <circle
28→        cx={start.x} cy={start.y} r={4}
29→        fill="var(--color-selection)"
30→        vectorEffect="non-scaling-stroke"
31→      />
32→      <circle
33→        cx={preview.x} cy={preview.y} r={4}
34→        fill="var(--color-selection)"
35→        vectorEffect="non-scaling-stroke"
36→      />
37→      <text
38→        x={midX} y={midY}
39→        textAnchor="middle"
40→        dy={-PREVIEW_LABEL_OFFSET}
41→        fill="var(--color-selection)"
42→        fontSize={140}
43→        fontFamily="var(--font-blueprint)"
44→      >
45→        {label}
46→      </text>
47→    </g>
48→  );
49→}
