  1→import { getColumnAutoLabel } from '@/domain/columnLabels';
  2→import { getBeamRenderData } from '@/geometry/beamGeometry';
  3→import { columnCenter } from '@/geometry/columnGeometry';
  4→import { add, perpendicular, scale } from '@/geometry/point';
  5→import { doorOutlineOnWall, wallDirection, windowOutlineOnWall } from '@/geometry/wallGeometry';
  6→
  7→function formatRoomArea(room) {
  8→  return room.area ? `${(room.area / 1_000_000).toFixed(1)} m²` : '';
  9→}
 10→
 11→function createTag(id, textLines, position, options = {}) {
 12→  const lines = textLines.filter(Boolean);
 13→  if (!lines.length) return null;
 14→
 15→  return {
 16→    id,
 17→    type: 'tag',
 18→    sourceType: options.sourceType ?? null,
 19→    sourceId: options.sourceId ?? null,
 20→    position,
 21→    angle: options.angle ?? 0,
 22→    textLines: lines,
 23→    textAnchor: options.textAnchor ?? 'middle',
 24→  };
 25→}
 26→
 27→function buildColumnTags(columns = []) {
 28→  return columns
 29→    .map((column, index) => createTag(
 30→      `column-tag-${column.id}`,
 31→      [column.name?.trim() || getColumnAutoLabel(column, columns) || `C${index + 1}`],
 32→      columnCenter(column),
 33→      { sourceType: 'column', sourceId: column.id }
 34→    ))
 35→    .filter(Boolean);
 36→}
 37→
 38→function buildBeamTags(beams = [], columns = []) {
 39→  return beams
 40→    .map((beam, index) => {
 41→      const renderData = getBeamRenderData(beam, columns || []);
 42→      if (!renderData) return null;
 43→      return createTag(
 44→        `beam-tag-${beam.id}`,
 45→        [`B${index + 1}`],
 46→        renderData.midpoint,
 47→        { sourceType: 'beam', sourceId: beam.id }
 48→      );
 49→    })
 50→    .filter(Boolean);
 51→}
 52→
 53→function buildRoomTags(rooms = []) {
 54→  return rooms
 55→    .map((room, index) => createTag(
 56→      `room-tag-${room.id}`,
 57→      [room.name?.trim() || `R${index + 1}`, formatRoomArea(room)],
 58→      room.labelPosition,
 59→      { sourceType: 'room', sourceId: room.id }
 60→    ))
 61→    .filter(Boolean);
 62→}
 63→
 64→function buildDoorTags(doors = [], walls = []) {
 65→  return doors
 66→    .map((door, index) => {
 67→      const wall = walls.find((entry) => entry.id === door.wallId);
 68→      if (!wall) return null;
 69→      const info = doorOutlineOnWall(wall, door);
 70→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 71→      return createTag(
 72→        `door-tag-${door.id}`,
 73→        [`D${index + 1}`],
 74→        add(info.center, offset),
 75→        { sourceType: 'door', sourceId: door.id }
 76→      );
 77→    })
 78→    .filter(Boolean);
 79→}
 80→
 81→function buildWindowTags(windows = [], walls = []) {
 82→  return windows
 83→    .map((windowItem, index) => {
 84→      const wall = walls.find((entry) => entry.id === windowItem.wallId);
 85→      if (!wall) return null;
 86→      const info = windowOutlineOnWall(wall, windowItem);
 87→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 88→      return createTag(
 89→        `window-tag-${windowItem.id}`,
 90→        [`W${index + 1}`],
 91→        add(info.center, offset),
 92→        { sourceType: 'window', sourceId: windowItem.id }
 93→      );
 94→    })
 95→    .filter(Boolean);
 96→}
 97→
 98→export function buildAnnotationTags(floor) {
 99→  return [
100→    ...buildColumnTags(floor.columns || []),
101→    ...buildBeamTags(floor.beams || [], floor.columns || []),
102→    ...buildRoomTags(floor.rooms || []),
103→    ...buildDoorTags(floor.doors || [], floor.walls || []),
104→    ...buildWindowTags(floor.windows || [], floor.walls || []),
105→  ];
106→}
